def precondition(rna: str) -> bool:
    """Check if the input RNA sequence is valid."""
    return isinstance(rna, str) and set(rna).issubset('ACGU')

def precondition(rna: str) -> bool:
    """Check if the input RNA sequence is a string consisting only of the characters A, C, G, and U."""
    return isinstance(rna, str) and set(rna).issubset('ACGU')

specs.postcondition_src:
def postcondition(rna: str, result: list[tuple[int, str]]) -> bool:
    """Check if the result is a list of tuples containing a start index and a protein string."""
    if not isinstance(result, list) or not all(isinstance(item, tuple) and len(item) == 2 for item in result):
        return False

    codon_table = {
        'AUG': 'M', 'UUU': 'F', 'UUC': 'F', 'UUA': 'L', 'UUG': 'L',
        'UCU': 'S', 'UCC': 'S', 'UCA': 'S', 'UCG': 'S', 'UAU': 'Y',
        'UAC': 'Y', 'UAA': '', 'UAG': '', 'UGU': 'C', 'UGC': 'C',
        'UGA': '', 'UGG': 'W', 'CUU': 'L', 'CUC': 'L', 'CUA': 'L',
        'CUG': 'L', 'AUU': 'I', 'AUC': 'I', 'AUA': 'I', 'GUU': 'V',
        'GUC': 'V', 'GUA': 'V', 'GUG': 'V', 'CCC': 'P', 'CCA': 'P',
        'CCG': 'P', 'CUC': 'L', 'ACU': 'T', 'ACC': 'T', 'ACA': 'T',
        'ACG': 'T', 'AAC': 'N', 'AAU': 'N', 'AAA': 'K', 'AAG': 'K',
        'AGC': 'S', 'AGU': 'S', 'AGA': 'R', 'AGG': 'R', 'GCU': 'A',
        'GCC': 'A', 'GCA': 'A', 'GCG': 'A', 'GAU': 'D', 'GAC': 'D',
        'GAA': 'E', 'GAG': 'E', 'GGU': 'G', 'GGC': 'G', 'GGA': 'G',
        'GGG': 'G'
    }

    for start_index, protein_string in result:
        if not isinstance(start_index, int) or start_index < 0 or start_index >= len(rna):
            return False

        if not isinstance(protein_string, str):
            return False

        orf_sequence = rna[start_index:]
        codons = [orf_sequence[i:i+3] for i in range(0, len(orf_sequence), 3)]

        if codons[0] != 'AUG':
            return False

        protein = ''
        for codon in codons:
            if codon in ['UAA', 'UAG', 'UGA']:
                break
            protein += codon_table.get(codon, '')

        if protein != protein_string:
            return False

    # Check that the list is sorted by start index
    return all(result[i][0] <= result[i+1][0] for i in range(len(result)-1))
